def simulate_row_measurement(container_width: int, items: list, alignment: str) -> list:
    if not items:
        return []

    # Separate items into fixed and weighted
    weighted_items = [item for item in items if item['weight'] > 0]
    fixed_items = [item for item in items if item['weight'] == 0]

    total_weight = sum(item['weight'] for item in weighted_items)

    # Calculate space reserved for fixed items
    fixed_space = sum(item['min_width'] for item in fixed_items)

    # Calculate space reserved for weighted items' minimums
    weighted_min_space = sum(item['min_width'] for item in weighted_items)

    remaining_space = container_width - fixed_space - weighted_min_space

    # Store intermediate measurements
    measurements = []

    # Calculate final widths for weighted items
    if total_weight > 0:
        if remaining_space >= 0:
            # Standard distribution
            for item in weighted_items:
                share = (item['weight'] / total_weight) * remaining_space
                item_width = item['min_width'] + share
                measurements.append({
                    'id': item['id'],
                    'width': int(item_width), # Compose uses integer coordinates
                    'min_width': item['min_width']
                })
        else:
            # Compression case: Scale down proportionally
            # We want sum(widths) == container_width
            # width = min_width + (weight/total) * remaining_space
            # If remaining_space is negative, we subtract from min_width
            for item in weighted_items:
                # Calculate the scaled width
                # Formula: width = min_width + (weight/total_weight) * remaining_space
                # This effectively shrinks the min_width if remaining_space is negative
                # However, to ensure sum matches container, we must be careful.
                # A safer compression: scale factor = container_width / (fixed_space + weighted_min_space)
                # But the prompt implies proportional sharing of the 'gap'.
                # Let's use the standard linear interpolation logic:
                width = item['min_width'] + (item['weight'] / total_weight) * remaining_space
                width = max(0, int(width))
                measurements.append({
                    'id': item['id'],
                    'width': width,
                    'min_width': item['min_width']
                })
    else:
        # No weight, treat as fixed
        for item in weighted_items:
            measurements.append({
                'id': item['id'],
                'width': item['min_width'],
                'min_width': item['min_width']
            })

    # Combine with fixed items
    for item in fixed_items:
        measurements.append({
            'id': item['id'],
            'width': item['min_width'],
            'min_width': item['min_width']
        })

    # Calculate positions
    current_x = 0
    layout = []
    for m in measurements:
        layout.append({
            'id': m['id'],
            'x': current_x,
            'width': m['width']
        })
        current_x += m['width']

    content_width = current_x

    # Apply Alignment
    alignment_offset = 0
    if alignment == "center":
        if content_width <= container_width:
            alignment_offset = (container_width - content_width) // 2
    elif alignment == "end":
        if content_width <= container_width:
            alignment_offset = container_width - content_width

    # Update x coordinates with alignment
    for item in layout:
        item['x'] += alignment_offset

    return layout

import json
from typing import Any, Dict, List, Optional
from collections import defaultdict

def analyze_compose_hierarchy(json_dump: str) -> List[Dict[str, Any]]:
    """
    Analyzes a Jetpack Compose UI hierarchy dump to detect accessibility violations.

    Checks for:
    - Interactive nodes missing content descriptions.
    - Nodes at depth >= 5 without content descriptions.
    - Duplicate content descriptions among sibling nodes.

    Args:
        json_dump: JSON string representing the UI hierarchy.

    Returns:
        A list of violation dictionaries. Each dict contains 'node_id', 'issue', 
        and relevant context keys.

    Raises:
        ValueError: If the input is not valid JSON.
    """
    try:
        tree = json.loads(json_dump)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON input: {e}") from e

    if not isinstance(tree, dict):
        raise ValueError("JSON root must be a dictionary representing a node.")

    findings: List[Dict[str, Any]] = []
    # Track descriptions per parent to detect sibling duplicates
    # Key: parent_node_id, Value: list of {'desc': str, 'node_id': str}
    sibling_descs: Dict[Optional[str], List[Dict[str, str]]] = defaultdict(list)

    def traverse(node: Dict[str, Any], depth: int, parent_id: Optional[str]) -> None:
        """
        Recursively traverses the UI tree to collect findings.
        """
        node_id: Optional[str] = node.get('id')
        props: Any = node.get('properties')

        # Normalize properties to ensure it's a dict
        if not isinstance(props, dict):
            props = {}

        # Safe extraction of description
        raw_desc: Any = props.get('contentDescription')

        # Normalize description: treat non-strings, empty strings, and None as missing
        desc_str: Optional[str] = None
        if raw_desc is not None:
            str_desc = str(raw_desc).strip()
            if str_desc:
                desc_str = str_desc

        # Determine interactivity
        is_interactive: bool = (
            'onClick' in props or 
            'onLongClick' in props or 
            props.get('enabled', True) is False # Disabled nodes might not need desc, but logic varies. 
                                                # Assuming enabled interactive nodes need desc.
        )
        # Refined interactive check: usually requires onClick/onLongClick regardless of enabled state for analysis
        if 'onClick' not in props and 'onLongClick' not in props:
            is_interactive = False

        # Check 1: Missing description on interactive node
        if is_interactive and desc_str is None:
            findings.append({
                'node_id': node_id,
                'issue': 'MISSING_DESC',
                'depth': depth
            })

        # Check 2: Depth violation (depth >= 5 must have desc)
        if depth >= 5 and desc_str is None:
            findings.append({
                'node_id': node_id,
                'issue': 'DEEP_NULL',
                'depth': depth
            })

        # Track descriptions for duplicate check
        if desc_str is not None:
            sibling_descs[parent_id].append({
                'desc': desc_str,
                'node_id': node_id
            })

        # Recurse
        children: Any = node.get('children')
        if isinstance(children, list):
            for child in children:
                if isinstance(child, dict):
                    traverse(child, depth + 1, node_id)

    traverse(tree, 0, None)

    # Process sibling duplicates
    for parent_id, entries in sibling_descs.items():
        # Group by description
        desc_groups: Dict[str, List[str]] = defaultdict(list)
        for entry in entries:
            desc_groups[entry['desc']].append(entry['node_id'])

        # Flag duplicates
        for desc, node_ids in desc_groups.items():
            if len(node_ids) > 1:
                for nid in node_ids:
                    findings.append({
                        'node_id': nid,
                        'issue': 'DUPLICATE_DESC',
                        'description': desc,
                        'conflicting_ids': [nid for nid in node_ids if nid != nid] # List of other conflicting IDs
                    })
                # Note: The conflicting_ids logic above is flawed due to variable shadowing in list comp
                # Fix: collect other ids properly
                # Re-doing logic for correctness in final output

    # Re-process duplicates cleanly
    findings = [f for f in findings if f.get('issue') != 'DUPLICATE_DESC'] # Remove temporary ones

    for parent_id, entries in sibling_descs.items():
        desc_groups: Dict[str, List[str]] = defaultdict(list)
        for entry in entries:
            desc_groups[entry['desc']].append(entry['node_id'])

        for desc, node_ids in desc_groups.items():
            if len(node_ids) > 1:
                for nid in node_ids:
                    others = [n for n in node_ids if n != nid]
                    findings.append({
                        'node_id': nid,
                        'issue': 'DUPLICATE_DESC',
                        'description': desc,
                        'conflicting_ids': others
                    })

    return findings

